# cost_per_request.py — track Claude API cost efficiency per quarter
from dataclasses import dataclass

# Anthropic pricing (input/output tokens per million) — update when pricing changes
MODEL_PRICING = {
    "claude-opus-4-8":          {"input": 15.00, "output": 75.00},
    "claude-sonnet-5":          {"input":  3.00, "output": 15.00},
    "claude-haiku-4-5-20251001":{"input":  0.80, "output":  4.00},
}

@dataclass
class QuarterlyUsage:
    model: str
    total_requests: int
    total_input_tokens: int
    total_output_tokens: int

    @property
    def cost_usd(self) -> float:
        pricing = MODEL_PRICING[self.model]
        return (
            self.total_input_tokens  / 1_000_000 * pricing["input"] +
            self.total_output_tokens / 1_000_000 * pricing["output"]
        )

    @property
    def cost_per_request_cents(self) -> float:
        return (self.cost_usd / self.total_requests) * 100 if self.total_requests else 0

    @property
    def avg_input_tokens(self) -> float:
        return self.total_input_tokens / self.total_requests if self.total_requests else 0

    @property
    def avg_output_tokens(self) -> float:
        return self.total_output_tokens / self.total_requests if self.total_requests else 0

# Q1 actual
q1 = QuarterlyUsage(
    model="claude-sonnet-5",
    total_requests=4_200_000,
    total_input_tokens=12_600_000_000,
    total_output_tokens=2_100_000_000,
)
print(f"Q1 cost: ${q1.cost_usd:,.0f}")
print(f"Q1 cost per request: {q1.cost_per_request_cents:.2f}¢")
print(f"Q1 avg input tokens: {q1.avg_input_tokens:.0f} | avg output tokens: {q1.avg_output_tokens:.0f}")
